// Time:  O(n * m)
// Space: O(n + m)

class Solution {
public:
    string largestMerge(string word1, string word2) {
        queue<char> q1, q2;
        for (const auto& c : word1) {
            q1.emplace(c);
        }
        for (const auto& c : word2) {
            q2.emplace(c);
        }
        string result;
        while (!empty(q1) || !empty(q2)) {
            if (q1 < q2) {
                swap(q1, q2);
            }
            result.push_back(q1.front()); q1.pop();
        }
        return result;
    }
};

# Time:  O(n * m)
# Space: O(n + m)

import collections


class Solution(object):
    def largestMerge(self, word1, word2):
        """
        :type word1: str
        :type word2: str
        :rtype: str
        """
        q1 = collections.deque(word1)
        q2 = collections.deque(word2)
        result = []
        while q1 or q2:
            if q1 > q2:
                result.append(q1.popleft())
            else:
                result.append(q2.popleft())
        return "".join(result)
